# =============================================================
# restore-unsynced-files.ps1
# 一鍵重建所有尚未同步到 GitHub 的檔案
# 使用方式: 在專案根目錄執行  .\restore-unsynced-files.ps1
# =============================================================

function Write-FileFromBase64 {
  param([string]$RelPath, [string]$B64Content)
  $dir = Split-Path $RelPath -Parent
  if ($dir -and !(Test-Path $dir)) {
    New-Item -ItemType Directory -Path $dir -Force | Out-Null
    Write-Host "  [DIR]  $dir" -ForegroundColor DarkCyan
  }
  $bytes = [Convert]::FromBase64String($B64Content)
  [System.IO.File]::WriteAllBytes((Resolve-Path . | Join-Path -ChildPath $RelPath), $bytes)
  Write-Host "  [OK]   $RelPath" -ForegroundColor Green
}

Write-Host ""
Write-Host "StockAnalyzeAI  還原未同步檔案" -ForegroundColor Cyan
Write-Host "======================================" -ForegroundColor DarkGray

Write-FileFromBase64 '.env.example' ''

